INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:1  
    
  Resol. do CM n.º 10-D/2020, de 19 de Março  (versão actualizada) DECLARA A SITUAÇÃO DE CALAMIDADE NO MUNICÍPIO DE OVAR    
    
 
  
                         
                          
SUMÁRIODeclara a situação de calamidade no município de Ovar, na sequência da situação epidemiológica da Covid-19
   
Resolução do Conselho de Ministros n.º 10-D/2020
                            
                           
                             
                               
                             
     Considerando a emergência de saúde pública de âmbito internacional, declarada pela Organização Mundial de Saúde, no dia 30 de janeiro de 2020, bem como a classificação, no dia 11 de março de 2020, da doença COVID-19 como uma pandemia, e bem assim a situação epidemiológica da COVID-19 em Portugal;
  Atendendo a que a autoridade de saúde do município de Ovar reconheceu que o município se encontra numa situação epidemiológica compatível com transmissão comunitária ativa, o que significa que o risco de transmissão se encontra generalizado, podendo mesmo dar origem a novas cadeias de transmissão em zonas vizinhas;
  Considerando que a avaliação agora efetuada no município de Ovar ainda não é suscetível, pelas suas características demográficas, sociais e económicas, de determinar a metodologia de definição futura dos mecanismos de atuação territorial em matéria de contenção da transmissão comunitária, mas que é fundamental conter as possíveis linhas de contágio para controlar a situação epidemiológica em Portugal;
  Nesse sentido, pelo Despacho n.º 3372-C/2020, publicado no Diário da República, 2.ª série, n.º 54, de 17 de março de 2020, o Primeiro-Ministro e o Ministro da Administração Interna reconheceram antecipadamente, ao abrigo dos artigos 20.º e 30.º da Lei de Bases da Proteção Civil, aprovada pela Lei n.º 27/2006, de 3 de julho, na sua redação atual (Lei de Bases da Proteção Civil), a necessidade de declarar a situação de calamidade no município de Ovar.
  Nos termos dos artigos 19.º e 20.º da Lei de Bases da Proteção Civil, ao despacho de reconhecimento antecipado sucede a resolução do Conselho de Ministros que declara a situação de calamidade.
  Assim:
  Nos termos dos artigos 19.º e 20.º da Lei n.º 27/2006, de 3 de julho, na sua redação atual, e da alínea g) do artigo 199.º da Constituição, o Conselho de Ministros resolve:
  1 - Declarar, nos termos do Despacho n.º 3372-C/2020, do Primeiro-Ministro e do Ministro da Administração Interna, publicado no Diário da República, 2.ª série, n.º 54, de 17 de março de 2020, a situação de calamidade no município de Ovar, na sequência da situação epidemiológica da COVID-19, que vigora até 2 de abril de 2020, sem prejuízo de prorrogação ou modificação na medida em que a evolução da situação epidemiológica o justificar.
  2 - Determinar a adoção das seguintes medidas, de caráter excecional, na área geográfica do município de Ovar:
  a) É interditada a circulação e permanência de pessoa','630');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('s na via pública, exceto para deslocações necessárias e urgentes, nomeadamente para:
  i) Venda e aquisição de bens alimentares, de higiene ou farmacêuticos, bem como de outros transacionados nos estabelecimentos previstos na alínea b) seguinte;
  ii) Acesso a unidades de cuidados de saúde;
  iii) Acesso ao local de trabalho, situado no município;
  iv) Assistência e cuidado a idosos, menores, dependentes e pessoas especialmente vulneráveis;
  b) É imposto o encerramento de:
  i) Todos os serviços públicos, da administração central ou local, exceto hospitais e centros de saúde, unidades militares, forças e serviços de segurança, serviços de socorro, comunicações, abastecimento de água e energia e recolha e tratamento de resíduos;
  ii) Estabelecimentos comerciais e de serviços, exceto os de venda a retalho de bens alimentares e de saúde e higiene, designadamente mercearias, padarias, minimercados, supermercados e hipermercados, bem como farmácias, bancos e postos de abastecimento de combustíveis, venda de jornais, revistas e tabaco, e de estabelecimentos de serviços de manutenção e reparação de veículos motorizados, e equipamentos informáticos e atividades funerárias e conexas;
  iii) Estabelecimentos industriais, com exceção daqueles relativos a setores essenciais ao funcionamento da vida coletiva, como os destinados à alimentação e à saúde humanas e animais e respetivas embalagens;
  iv) Outros estabelecimentos, em casos de força maior, em condições acordadas pelas autoridades de saúde pública, devidamente autorizados por despacho conjunto dos membros do Governo responsáveis pelas áreas da economia, da administração interna e da saúde;
  c) É fixada uma cerca sanitária municipal, estando interditadas as deslocações por via rodoviária de e para o município de Ovar, exceto aquelas:
  i) De profissionais de saúde e de medicina veterinária, elementos das forças armadas e das forças e serviços de segurança, serviços de socorro e empresas de segurança privada;
  ii) De regresso ao local de residência habitual;
  iii) Para abastecimento do comércio e produção alimentar, farmacêutico, de combustíveis e de outros bens essenciais, bem como o transporte de mercadorias necessárias ao funcionamento das empresas em laboração, excecionadas na alínea b);
  iv) Para abastecimento de terminais de caixa automático;
  v) Para reparação e manutenção de infraestruturas de comunicações, de esgotos, de águas, de transporte de eletricidade, de transporte de gás e de outras cujas características e caráter urgente não possam ser adiadas;
  vi) Justificadas por razões de urgência, devidamente fundamentada, ou casos de força maior ou de saúde pública;
  d) É proibida a tomada e largada de passageiros do transporte ferroviário nas estações e apeadeiros do município de Ovar.
  3 - Reforçar que, durante o período de vigência da situação de calamidade, os cidadãos e as demais entidades têm, nos termos dos n.os 1 a 3 do artigo 6.º da Lei n.º 27/2006, de 3 de julho, na sua redaç','630');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ão atual, o dever de colaboração, nomeadamente no cumprimento de ordens ou instruções dos órgãos e agentes responsáveis pela segurança interna e pela proteção civil e na pronta satisfação de solicitações que justificadamente lhes sejam feitas pelas entidades competentes para a concretização das medidas que justificam a presente declaração.
  4 - Reforçar que a desobediência e a resistência às ordens legítimas das entidades competentes, quando praticadas durante a vigência da situação de calamidade, constituem crime e são sancionadas nos termos da lei penal, sendo as respetivas penas agravadas em um terço, nos seus limites mínimo e máximo, nos termos do n.º 4 do artigo 6.º da Lei n.º 27/2006, de 3 de julho, na sua redação atual.
  5 - Ativar a comissão municipal de proteção civil de Ovar e acionado o respetivo plano municipal de emergência de proteção civil.
  6 - Determinar que a atividade operacional das forças e serviços de segurança e serviços de socorro a operar no município de Ovar, no âmbito da execução da presente declaração, pode ser reforçada, em caso de necessidade, por efetivos de outras áreas geográficas, mediante coordenação pela estrutura municipal de proteção civil.
  7 - Determinar que a presente resolução produz efeitos imediatos.
  
  Presidência do Conselho de Ministros, 18 de março de 2020. - O Primeiro-Ministro, António Luís Santos da Costa.','630');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:8  
    
  Decreto do PR n.º 14-A/2020, de 18 de Março  (versão actualizada) DECLARA O ESTADO DE EMERGÊNCIA    
    
 
  
                         
                          
SUMÁRIODeclara o estado de emergência, com fundamento na verificação de uma situação de calamidade pública
Decreto do Presidente da República n.º 14-A/2020, de 18 de março
  A Organização Mundial de Saúde qualificou, no passado dia 11 de março de 2020, a emergência de saúde pública ocasionada pela doença COVID-19 como uma pandemia internacional, constituindo uma calamidade pública.
  A situação tem evoluído muito rapidamente em todo o mundo em geral, e, em particular, na União Europeia. Em face do que antecede, têm sido adotadas medidas de forte restrição de direitos e liberdades, em especial no que respeita aos direitos de circulação e às liberdades económicas, procurando assim prevenir a transmissão do vírus.
  Portugal não se encontra imune a esta realidade. Bem pelo contrário, são crescentes os novos casos de infetados no nosso País. O conhecimento hoje adquirido e a experiência de outros países aconselham a que idênticas medidas sejam adotadas em Portugal, como forma de conter a expansão da doença, sempre em estreita articulação com as autoridades europeias.
  Em Portugal, foram já adotadas diversas medidas importantes de contenção, as quais foram, de imediato, promulgadas pelo Presidente da República, e declarado o estado de alerta, ao abrigo do disposto na Lei de Bases da Proteção Civil.
  Contudo, à semelhança do que está a ocorrer noutros países europeus, torna-se necessário reforçar a cobertura constitucional a medidas mais abrangentes, que se revele necessário adotar para combater esta calamidade pública, razão pela qual o Presidente da República entende ser indispensável a declaração do estado de emergência.
  Nos termos constitucionais e legais, a declaração limita-se ao estritamente necessário para a adoção das referidas medidas e os seus efeitos terminarão logo que a normalidade seja retomada. Entretanto, confere às medidas que se traduzam em limitações de direitos, liberdades e garantias o respaldo Constitucional que só o estado de emergência pode dar, reforçando a segurança e certeza jurídicas e a solidariedade institucional.
  Foram consideradas, em articulação com o Governo, as posições da Autoridade de Saúde Nacional.
  Foi ouvido o Conselho de Estado.
  Nestes termos, o Presidente da República decreta, nos termos dos artigos 19.º, 134.º, alínea d), e 138.º da Constituição e da Lei n.º 44/86, de 30 de setembro, alterada pela Lei Orgânica n.º 1/2011, de 30 de novembro, e pela Lei Orgânica n.º 1/2012, de 11 de maio, ouvido o Governo e obtida a necessária autorização da Assembleia da República, através da Resolução da Assembleia da República n.º 15-A/2020, de 18 de março, o seguinte:
  
  1.º
                            
                           
                             
                               
                             
     ','630');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('É declarado o estado de emergência, com fundamento na verificação de uma situação de calamidade pública.            
         
   
     
                         
                          
  2.º
                            
                           
                             
                               
                             
     A declaração de estado de emergência abrange todo o território nacional.            
         
   
     
                         
                          
  3.º
                            
                           
                             
                               
                             
     O estado de emergência tem a duração de 15 dias, iniciando-se às 0:00 horas do dia 19 de março de 2020 e cessando às 23:59 horas do dia 2 de abril de 2020, sem prejuízo de eventuais renovações, nos termos da lei.            
         
   
     
                         
                          
  4.º
                            
                           
                             
                               
                             
     Fica parcialmente suspenso o exercício dos seguintes direitos:
  a) Direito de deslocação e fixação em qualquer parte do território nacional: podem ser impostas pelas autoridades públicas competentes as restrições necessárias para reduzir o risco de contágio e executar as medidas de prevenção e combate à epidemia, incluindo o confinamento compulsivo no domicílio ou em estabelecimento de saúde, o estabelecimento de cercas sanitárias, assim como, na medida do estritamente necessário e de forma proporcional, a interdição das deslocações e da permanência na via pública que não sejam justificadas, designadamente pelo desempenho de atividades profissionais, pela obtenção de cuidados de saúde, pela assistência a terceiros, pelo abastecimento de bens e serviços e por outras razões ponderosas, cabendo ao Governo, nesta eventualidade, especificar as situações e finalidades em que a liberdade de circulação individual, preferencialmente desacompanhada, se mantém;
  b) Propriedade e iniciativa económica privada: pode ser requisitada pelas autoridades públicas competentes a prestação de quaisquer serviços e a utilização de bens móveis e imóveis, de unidades de prestação de cuidados de saúde, de estabelecimentos comerciais e industriais, de empresas e outras unidades produtivas, assim como pode ser determinada a obrigatoriedade de abertura, laboração e funcionamento de empresas, estabelecimentos e meios de produção ou o seu encerramento e impostas outras limitações ou modificações à respetiva atividade, incluindo alterações à quantidade, natureza ou preço dos bens produzidos e comercializados ou aos respetivos procedimentos e circuitos de distribuição e comercialização, bem como alterações ao respetivo regime de funcionamento;
  c) Direitos dos trabalhadores: pode ser determinado pelas autoridades públicas competentes que quaisquer colaboradores de entidade','630');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('s públicas ou privadas, independentemente do tipo de vínculo, se apresentem ao serviço e, se necessário, passem a desempenhar funções em local diverso, em entidade diversa e em condições e horários de trabalho diversos dos que correspondem ao vínculo existente, designadamente no caso de trabalhadores dos setores da saúde, proteção civil, segurança e defesa e ainda de outras atividades necessárias ao tratamento de doentes, à prevenção e combate à propagação da epidemia, à produção, distribuição e abastecimento de bens e serviços essenciais, ao funcionamento de setores vitais da economia, à operacionalidade de redes e infraestruturas críticas e à manutenção da ordem pública e do Estado de Direito democrático. Fica suspenso o exercício do direito à greve na medida em que possa comprometer o funcionamento de infraestruturas críticas ou de unidades de prestação de cuidados de saúde, bem como em setores económicos vitais para a produção, abastecimento e fornecimento de bens e serviços essenciais à população;
  d) Circulação internacional: podem ser estabelecidos pelas autoridades públicas competentes, em articulação com as autoridades europeias e em estrito respeito pelos Tratados da União Europeia, controlos fronteiriços de pessoas e bens, incluindo controlos sanitários em portos e aeroportos, com a finalidade de impedir a entrada em território nacional ou de condicionar essa entrada à observância das condições necessárias a evitar o risco de propagação da epidemia ou de sobrecarga dos recursos afetos ao seu combate, designadamente impondo o confinamento compulsivo de pessoas. Podem igualmente ser tomadas as medidas necessárias a assegurar a circulação internacional de bens e serviços essenciais;
  e) Direito de reunião e de manifestação: podem ser impostas pelas autoridades públicas competentes, com base na posição da Autoridade de Saúde Nacional, as restrições necessárias para reduzir o risco de contágio e executar as medidas de prevenção e combate à epidemia, incluindo a limitação ou proibição de realização de reuniões ou manifestações que, pelo número de pessoas envolvidas, potenciem a transmissão do novo Coronavírus;
  f) Liberdade de culto, na sua dimensão coletiva: podem ser impostas pelas autoridades públicas competentes as restrições necessárias para reduzir o risco de contágio e executar as medidas de prevenção e combate à epidemia, incluindo a limitação ou proibição de realização de celebrações de cariz religioso e de outros eventos de culto que impliquem uma aglomeração de pessoas;
  g) Direito de resistência: fica impedido todo e qualquer ato de resistência ativa ou passiva às ordens emanadas pelas autoridades públicas competentes em execução do presente estado de emergência.            
         
   
     
                         
                          
  5.º
                            
                           
                             
                               
                             
     1 - Os efeitos da pres','630');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ente declaração não afetam, em caso algum, os direitos à vida, à integridade pessoal, à identidade pessoal, à capacidade civil e à cidadania, à não retroatividade da lei criminal, à defesa dos arguidos e à liberdade de consciência e religião.
  2 - Os efeitos da presente declaração não afetam igualmente, em caso algum, as liberdades de expressão e de informação.
  3 - Em caso algum pode ser posto em causa o princípio do Estado unitário ou a continuidade territorial do Estado.
  4 - Nos termos da lei, a Procuradoria-Geral da República e a Provedoria de Justiça mantêm-se em sessão permanente.            
         
   
     
                         
                          
  6.º
                            
                           
                             
                               
                             
     Os órgãos responsáveis, nos termos da Lei n.º 44/86, de 30 de setembro, pela execução da declaração do estado de emergência devem manter permanentemente informados o Presidente da República e a Assembleia da República dos atos em que consista essa execução.            
         
   
     
                         
                          
  7.º
                            
                           
                             
                               
                             
     São ratificadas todas as medidas legislativas e administrativas adotadas no contexto da presente crise, as quais dependam da declaração do estado de emergência.            
         
   
     
                         
                          
  8.º
                            
                           
                             
                               
                             
     O presente Decreto entra imediatamente em vigor, produzindo efeitos nos termos definidos no artigo 3.º
  
  Assinado em 18 de março de 2020.
  Publique-se.
  O Presidente da República, Marcelo Rebelo de Sousa.
  Referendado em 18 de março de 2020.
  O Primeiro-Ministro, António Luís Santos da Costa.','630');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:11  
    
  Resol. n.º 25/2008, de 18 de Julho  (versão actualizada) ELABORAÇÃO E OPERACIONALIZAÇÃO DE PLANOS DE EMERGÊNCIA DE PROTECÇÃO CIVIL    
    
 
Contém as seguintes alterações:   - Resol. n.º 30/2015, de 07 de Maio  
                         
                          
SUMÁRIOCritérios e normas técnicas para a elaboração e operacionalização de planos de emergência de protecção civil - Este diploma foi revogado pelo(a) Resolução n.º 30/2015, de 07 de Maio!
Resolução n.º 25/2008 
  Em conformidade com o previsto na alínea h) do n.º 2 do artigo 36.º e no n.º 1 do artigo 50.º, ambos da Lei de Bases de Protecção Civil, compete à Comissão Nacional de Protecção Civil emanar as directivas relativas à definição dos critérios e normas técnicas sobre a elaboração de planos de emergência. 
  Assim, nos termos e ao abrigo do disposto nos n.os 1 e 2 do artigo 7.º da Portaria n.º 302/2008, de 18 de Abril, a Comissão Nacional de Protecção Civil, em reunião realizada em 16 de Abril de 2008, deliberou: 
  
  1) Aprovar a directiva relativa aos critérios e normas técnicas para a elaboração e operacionalização de planos de emergência de protecção civil, que constitui anexo à presente resolução, da qual faz parte integrante; 
  
  2) Revogar a directiva para a elaboração de planos de emergência de protecção civil publicada, através de declaração do Gabinete do Ministro da Administração Interna, no Diário da República, 2.ª série, n.º 291, de 19 de Dezembro de 1994; 
  
  3) Determinar a entrada em vigor da presente resolução no 1.º dia útil seguinte ao da sua publicação no Diário da República. 
  
  30 de Junho de 2008. - O Presidente, José Miguel Abreu de Figueiredo Medeiros, Secretário de Estado da Protecção Civil. 
  
  ANEXO 
  Directiva relativa aos critérios e normas técnicas para a elaboração e operacionalização de planos de emergência de protecção civil 
  
  Os planos de emergência de protecção civil são documentos formais nos quais as autoridades de protecção civil, nos seus diversos níveis, definem as orientações relativamente ao modo de actuação dos vários organismos, serviços e estruturas a empenhar em operações de protecção civil. 
  Tais planos têm sido, até agora, elaborados de acordo com o disposto na directiva para a elaboração de planos de emergência de protecção civil, aprovada pela Comissão Nacional de Protecção Civil (CNPC) em 1994, importando proceder à actualização deste documento para o adequar ao novo enquadramento legal do Sistema de Protecção Civil, tomando em linha de consideração as boas práticas existentes no domínio da elaboração e operacionalização de planos de emergência de protecção civil. 
  Nesta revisão estabeleceu-se também uma maior interligação entre os mecanismos de planeamento de emergência de protecção civil e os instrumentos de planeamento e ordenamento do território. Essa interligação visa o estabelecimento de sinergias ao nível da identificação de riscos e vulnerabilidades e da harmonização de bases','630');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' cartográficas, considerando-se que os planos de emergência de protecção civil devem seguir o disposto no decreto regulamentar que fixa a cartografia a utilizar nos instrumentos de gestão territorial. 
  Por outro lado, clarifica-se o acesso público aos planos de emergência e garante-se a disponibilização das suas componentes não reservadas em plataformas baseadas nas tecnologias de informação e comunicação, promovendo a interacção com o cidadão. Este acesso permitirá um elevado grau de participação, responsabilização e acompanhamento das medidas adoptadas e uma maior proximidade aos diversos agentes de protecção civil, cumprindo um dos grandes objectivos do Programa do Governo inserido no plano tecnológico. A obrigatoriedade de os planos de emergência serem disponibilizados em formato digital, devidamente acompanhados de uma base de dados de meios e recursos e de um sistema de informação geográfica, facilitará ainda a sua rápida e permanente actualização. 
  Por último, com a presente directiva, normalizam-se a estrutura e os conteúdos dos planos de emergência, agilizando o seu processo de elaboração, revisão e aprovação e introduzindo mecanismos de verificação periódica da sua eficácia.  Artigo 1.º Finalidade e âmbito - revogado - Resolução n.º 30/2015, de 07 de Maio
                            
                           
                             
                               
                             
     1 - A presente directiva tem por finalidade proceder à revisão da directiva para a elaboração de planos de emergência de protecção civil, aprovada em 19 de Dezembro de 1994, e fixar, nos termos da Lei de Bases da Protecção Civil, os critérios e as normas técnicas para a sua elaboração e operacionalização. 
  2 - O disposto na presente directiva é aplicável a todas as entidades públicas ou privadas com competências no domínio da protecção civil.            
         
   
     
                         
                          
  Artigo 2.º Tipos - revogado - Resolução n.º 30/2015, de 07 de Maio
                            
                           
                             
                               
                             
     1 - Os planos de emergência de protecção civil são, consoante a sua finalidade, designados por planos gerais ou especiais. 
  2 - Os planos gerais elaboram-se para enfrentar a generalidade das situações de emergência que se admitem em cada âmbito territorial e administrativo. 
  3 - Os planos especiais são elaborados com o objectivo de serem aplicados quando ocorrerem acidentes graves e catástrofes específicas, cuja natureza requeira uma metodologia técnica e ou científica adequada ou cuja ocorrência no tempo e no espaço seja previsível com elevada probabilidade ou, mesmo com baixa probabilidade associada, possa vir a ter consequências inaceitáveis. 
  4 - Os planos de emergência de protecção civil, consoante a extensão territorial da situação visada, são nacionais, regionais, distritais ','630');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ou municipais. 
  5 - Os planos especiais de emergência de protecção civil podem também abranger áreas homogéneas de risco cuja extensão seja supramunicipal ou supradistrital.            
         
   
     
                         
                          
  Artigo 3.º Identificação - revogado - Resolução n.º 30/2015, de 07 de Maio
                            
                           
                             
                               
                             
     Os planos de emergência de protecção civil devem ser identificados da seguinte forma: 
  a) Plano Nacional de Emergência de Protecção Civil; 
  b) Plano (Regional, Distrital ou Municipal) de Emergência de Protecção Civil de (nome da Região Autónoma, distrito ou município); 
  c) Plano Especial de Emergência de Protecção Civil para (tipo de risco) em (área a que se refere).            
         
   
     
                         
                          
  Artigo 4.º Elaboração, aprovação e publicitação - revogado - Resolução n.º 30/2015, de 07 de Maio
                            
                           
                             
                               
                             
     1 - Os planos de emergência de âmbito nacional são elaborados pela Autoridade Nacional de Protecção Civil (ANPC) e aprovados pelo Conselho de Ministros, mediante parecer prévio da CNPC. 
  2 - Os planos de emergência de âmbito regional são elaborados pelos respectivos serviços regionais de protecção civil e aprovados pelos órgãos de governo próprio das Regiões, mediante parecer prévio da CNPC. 
  3 - Os planos de emergência de âmbito supradistrital são elaborados pela ANPC e aprovados pela CNPC. 
  4 - Os planos de emergência de âmbito distrital e supramunicipal são elaborados pelo governador civil e aprovados pela CNPC, mediante parecer prévio da Comissão Distrital de Protecção Civil (CDPC) e da ANPC. 
  5 - Os planos de emergência de âmbito municipal são elaborados pela câmara municipal e aprovados pela CNPC, mediante parecer prévio da Comissão Municipal de Protecção Civil (CMPC) e da ANPC. 
  6 - Os planos de emergência de âmbito municipal dos municípios das Regiões Autónomas são elaborados pela câmara municipal e aprovados pelo membro do Governo Regional que tutela o sector da protecção civil, mediante parecer prévio da CMPC e do Serviço Regional de Protecção Civil respectivos. 
  7 - Os planos especiais de emergência são aprovados pela CNPC, mediante parecer prévio das entidades legalmente competentes face à tipologia do risco considerada. 
  8 - A elaboração dos planos de emergência de protecção civil inclui uma fase de consulta pública das suas componentes não reservadas. 
  9 - A fase de consulta pública desenrola-se por um prazo não inferior a 30 dias e é promovida pela entidade responsável pela elaboração do plano que estabelece os meios e as formas de participação, devendo ser integradas no plano as observações pertinentes apresentadas. 
  10 - O relat','630');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ório da consulta pública deve ser submetido, pela entidade responsável pela elaboração do plano, à entidade responsável pela respectiva aprovação. 
  11 - As deliberações de aprovação dos planos de emergência de protecção civil são objecto de publicação no Diário da República pela entidade competente para a sua aprovação. 
  12 - Os planos de emergência entram em vigor no 1.º dia útil seguinte ao da publicação referida no número anterior.            
         
   
     
                         
                          
  Artigo 5.º Articulação - revogado - Resolução n.º 30/2015, de 07 de Maio
                            
                           
                             
                               
                             
     Para efeitos de harmonização de um plano de emergência em relação a outros, devem procurar-se as seguintes articulações: 
  a) Planos regionais/plano nacional; 
  b) Planos distritais/plano nacional; 
  c) Planos municipais/plano distrital respectivo/planos municipais adjacentes/ plano regional; 
  d) Planos especiais/planos gerais da área respectiva/planos especiais para o mesmo risco de outras áreas.            
         
   
     
                         
                          
  Artigo 6.º Revisão - revogado - Resolução n.º 30/2015, de 07 de Maio
                            
                           
                             
                               
                             
     1 - Os planos gerais de emergência devem ser revistos, no mínimo, bianualmente. 
  2 - Os planos especiais de emergência devem ser revistos, no mínimo, bianualmente, excepto se disposto em contrário em legislação específica referente à tipologia de risco considerada. 
  3 - Os planos de emergência devem ser obrigatoriamente revistos aquando da percepção de novos riscos ou da identificação de novas vulnerabilidades na respectiva área territorial. 
  4 - Na revisão dos planos de emergência devem ser tidos em conta os ensinamentos adquiridos aquando da realização de exercícios ou de anteriores activações dos planos, bem como as informações decorrentes de novos estudos ou relatórios de carácter técnico ou científico. 
  5 - A revisão dos planos de emergência deve seguir as formalidades de aprovação referidas no artigo 4.º da presente directiva, excepto quando se reportarem ao conteúdo da parte iv do índice de referência, caso em que devem ser aprovadas pela comissão de protecção civil territorialmente competente.            
         
   
     
                         
                          
  Artigo 7.º Distribuição - revogado - Resolução n.º 30/2015, de 07 de Maio
                            
                           
                             
                               
                             
     1 - Deve ser assegurada a distribuição dos planos de emergência aprovados, em formato digital, a todos os agentes, organismos e entidades nele mencionados, a todas as entidades integrante','630');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('s da comissão de protecção civil do respectivo nível territorial, às autoridades de protecção civil das unidades administrativas adjacentes de nível similar, à autoridade de protecção civil de nível territorial imediatamente superior e à ANPC. 
  2 - Deve ser ainda assegurada a disponibilização pública do corpo dos planos de emergência aprovados, usando suportes de tecnologias de informação e comunicação. 
  3 - Compete ao director de cada plano de emergência assegurar a sua distribuição e disponibilização pública, incluindo as versões revistas.            
         
   
     
                         
                          
  Artigo 8.º Conteúdo - revogado - Resolução n.º 30/2015, de 07 de Maio
                            
                           
                             
                               
                             
     1 - Os planos gerais de emergência devem incluir, no mínimo: 
  a) Enquadramento legal; 
  b) Antecedentes do processo de planeamento de emergência; 
  c) Referências geográficas à escala adequada, recorrendo à utilização de cartas, mapas e sistemas de informação geográfica; 
  d) Caracterização da situação de referência da área territorial do plano, em termos físicos e socioeconómicos; 
  e) Articulação com os planos de ordenamento do território (regionais, municipais, intermunicipais, sectoriais e especiais) em vigor na área do plano; 
  f) Caracterização da situação de referência relativamente aos riscos em análise, incluindo cronologia de eventos passados e identificação e descrição das metodologias utilizadas para a análise e avaliação de risco; 
  g) Descrição das características das infra-estruturas consideradas sensíveis e ou indispensáveis às operações de protecção civil; 
  h) Descrição dos diferentes cenários que estão na origem do plano; 
  i) Avaliação dos principais recursos (públicos e privados) existentes e mobilizáveis, incluindo listas detalhadas e actualizadas das equipas de especialistas em operações de socorro e salvamento, listas de peritos individuais nas matérias apropriadas, listas de equipamento especial, localização de estabelecimentos diversos e a indicação dos responsáveis pela manutenção e actualização destas; 
  j) Mecanismos e circunstâncias fundamentadoras para a activação formal do plano, o que determina o início da sua obrigatoriedade, em função dos cenários nele consideradas; 
  k) Designação do director do plano e seus substitutos, a quem corresponde a autoridade de coordenar a direcção das operações nele previstas; 
  l) Organização geral das operações de protecção civil a efectuar, incluindo o estabelecimento de fases e o desenvolvimento de fluxogramas dos procedimentos e actividades a adoptar; 
  m) Lista das autoridades, entidades e organismos que devem ser notificados da existência de acontecimentos susceptíveis de provocar danos em pessoas e bens; 
  n) Composição da estrutura operacional, considerando a incorporação de organismos especializados, pessoal téc','630');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('nico e peritos necessários; 
  o) Estrutura dos meios operacionais de resposta à emergência, a qual deve ser determinada em função da estrutura administrativa existente e em função dos tipos de emergência contemplados no plano; 
  p) Medidas e acções de socorro, tais como busca e salvamento, primeiros socorros, triagem, evacuação, cuidados de saúde primários, abrigos de emergência, abastecimento e sepultamentos de emergência, 
  q) Medidas de protecção dos bens, com especial atenção aos bens declarados de interesse cultural, patrimonial e ambiental; 
  r) Mecanismos adequados para a informação da população afectada e do público em geral, para que este possa adaptar a sua conduta à prevista no plano; 
  s) Localização principal e alternativa dos centros de coordenação operacional e das comissões de protecção civil territorialmente competentes, quando não definidas em regulamento próprio; 
  t) Orientações de funcionamento dos agentes, organismos e entidades envolvidas e critérios relativos à mobilização dos recursos, tanto do sector público como do sector privado; 
  u) Acordos ou protocolos de ajuda mútua existentes; 
  v) Medidas de reabilitação dos serviços públicos essenciais; 
  w) Medidas de validação e manutenção da eficácia do plano, que compreendem formação, verificação periódica, exercícios e simulacros; 
  x) Fontes de informação utilizadas na elaboração do plano. 
  2 - Os planos especiais de emergência podem seguir uma tipologia de conteúdos simplificada face à descrita no n.º 1 anterior, desde que tal conteúdo conste do Plano Geral de Emergência do mesmo nível territorial. 
  3 - Os planos especiais de emergência devem ainda, quando aplicável, assegurar o conteúdo mínimo exigido nos respectivos instrumentos legais sectoriais.            
         
   
     
                         
                          
  Artigo 9.º Exercícios - revogado - Resolução n.º 30/2015, de 07 de Maio
                            
                           
                             
                               
                             
     1 - A realização de exercícios tem como finalidade testar a operacionalidade dos planos, manter a prontidão e assegurar a eficiência de todos os agentes de protecção civil e garantir a manutenção da eficácia do plano e das organizações intervenientes. 
  2 - Excepto se disposto em contrário em legislação sectorial específica, os planos de emergência devem ser objecto de exercícios pelo menos bianualmente. 
  3 - Sem prejuízo da periodicidade referida no número anterior, a primeira revisão de um plano de emergência, após a publicação da presente directiva, deve ser seguida da realização de um exercício no prazo máximo de 180 dias após a aprovação da revisão.            
         
   
     
                         
                          
  Artigo 10.º Disposições finais - revogado - Resolução n.º 30/2015, de 07 de Maio
                            
                           
                           ','630');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('  
                               
                             
     1 - O anexo à presente directiva constitui o índice de referência a servir de base à elaboração dos planos de emergência. 
  2 - Os planos de emergência são documentos de carácter público, exceptuando-se as secções ii e iii da parte iv do seu índice de referência, cujo conteúdo é considerado reservado. 
  3 - Sem prejuízo do disposto em legislação específica, os planos de emergência que se encontram elaborados à data de aprovação da presente directiva devem ser revistos no prazo máximo de dois anos, de forma a ficarem em conformidade com a presente directiva. 
  4 - Os planos de emergência devem seguir a terminologia específica utilizada no glossário próprio adoptado pela CNPC. 
  5 - A ANPC desenvolve e divulga os guias de apoio à elaboração e operacionalização dos planos de emergência de protecção civil.            
         
   
     
                         
                          
