INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('entes do disposto no presente decreto-lei respeitantes à produção, comercialização e exportação de coníferas hospedeiras destinadas à plantação e respeitantes à exportação de madeira de coníferas são devidas as taxas previstas no artigo 25.º do Decreto-Lei n.º 154/2005, de 6 de setembro.
